package src.org.apache.nutch.webui.service.impl;

@ Service public class CrawlServiceImpl implements CrawlService , CrawlingCycleListener { private static final Logger LOG = LoggerFactory . getLogger ( MethodHandles . lookup ( ) . lookupClass ( ) ) ; @ Resource private Dao < Crawl , Long > crawlDao ; @ Resource private NutchClientFactory nutchClientFactory ; @ Resource private RemoteCommandsBatchFactory commandFactory ; @ Override @ Async public void startCrawl ( Long crawlId , NutchInstance instance ) { Crawl crawl = null ; try { crawl = crawlDao . queryForId ( crawlId ) ; if ( crawl . getCrawlId ( ) == null ) { crawl . setCrawlId ( "crawl-" + crawlId . toString ( ) ) ; } NutchClient client = nutchClientFactory . getClient ( instance ) ; String seedDirectory = client . createSeed ( crawl . getSeedList ( ) ) ; crawl . setSeedDirectory ( seedDirectory ) ; List < RemoteCommand > commands = commandFactory . createCommands ( crawl ) ; RemoteCommandExecutor executor = new RemoteCommandExecutor ( client ) ; CrawlingCycle cycle = new CrawlingCycle ( this , executor , crawl , commands ) ; cycle . executeCrawlCycle ( ) ; } catch ( Exception e ) { crawl . setStatus ( CrawlStatus . ERROR ) ; saveCrawl ( crawl ) ; LOG . error ( "exception occured" , e ) ; } } @ Override public List < Crawl > getCrawls ( ) { try { return crawlDao . queryForAll ( ) ; } catch ( SQLException e ) { throw new RuntimeException ( e ) ; } } @ Override public void saveCrawl ( Crawl crawl ) { try { crawlDao . createOrUpdate ( crawl ) ; } catch ( SQLException e ) { throw new RuntimeException ( e ) ; } } @ Override public void deleteCrawl ( Long crawlId ) { try { crawlDao . deleteById ( crawlId ) ; } catch ( SQLException e ) { throw new RuntimeException ( e ) ; } } @ Override public void crawlingStarted ( Crawl crawl ) { crawl . setStatus ( CrawlStatus . CRAWLING ) ; crawl . setProgress ( 0 ) ; saveCrawl ( crawl ) ; } @ Override public void onCrawlError ( Crawl crawl , String msg ) { crawl . setStatus ( CrawlStatus . ERROR ) ; saveCrawl ( crawl ) ; } @ Override public void commandExecuted ( Crawl crawl , RemoteCommand command , int progress ) { crawl . setProgress ( progress ) ; saveCrawl ( crawl ) ; } @ Override public void crawlingFinished ( Crawl crawl ) { crawl . setStatus ( CrawlStatus . FINISHED ) ; saveCrawl ( crawl ) ; } }